from typing import Callable, Any, Dict
import logging

logger = logging.getLogger(__name__)

class TaskQueue:
    def __init__(self, max_size: int = 1000):
        self._queue = deque(maxlen=max_size)

    def enqueue(self, task: Callable, **kwargs: Any) -> None:
        self._queue.append({'task': task, 'kwargs': kwargs})
        logger.info(f'Task enqueued. Queue size: {len(self._queue)}')

    def process_next(self) -> Any:
        if not self._queue:
            return None
        item = self._queue.popleft()
        return item['task'](**item['kwargs'])

