import logging

logger = logging.getLogger(__name__)

class ScheduledTask:
    def __init__(self, name: str, fn: Callable, interval: timedelta):
        self.name = name
        self.fn = fn
        self.interval = interval
        self.last_run: Optional[datetime] = None

    def is_due(self) -> bool:
        if self.last_run is None:
            return True
        return datetime.now() - self.last_run >= self.interval

class TaskScheduler:
    def __init__(self):
        self._tasks: List[ScheduledTask] = []

    def register(self, name: str, fn: Callable, interval: timedelta) -> None:
        self._tasks.append(ScheduledTask(name, fn, interval))
        logger.info(f'Registered task: {name} (every {interval})')

    def run_due_tasks(self) -> int:
        count = 0
        for task in self._tasks:
            if task.is_due():
                task.fn()
                task.last_run = datetime.now()
                count += 1
        return count

